/* Decodeur : reconstruit le Set a partir du front-coding.
   Chaque ligne = <1 char longueur prefixe partage><suffixe>. */
function _decLen(c){
  const x=c.charCodeAt(0);
  if(x>=48&&x<=57)return x-48;      // 0-9
  if(x>=65&&x<=90)return x-55;      // A-Z -> 10-35
  return x-61;                      // a-z -> 36-61
}
/* Replie les accents : ecole -> ecole, garcon -> garcon (saisie mobile) */
function foldAccents(w){
  return (w||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'')
    .replace(/œ/g,'oe').replace(/æ/g,'ae').replace(/ç/g,'c');
}
let DICT_FR=null, DICT_FR_FOLD=null;
function _buildFR(){
  if(DICT_FR)return DICT_FR;
  DICT_FR=new Set(); DICT_FR_FOLD=new Set();
  const lines=_FR_BLOB.split('\n');
  let prev='';
  for(let i=0;i<lines.length;i++){
    const ln=lines[i]; if(!ln){continue;}
    const p=_decLen(ln[0]);
    const w=prev.slice(0,p)+ln.slice(1);
    DICT_FR.add(w); DICT_FR_FOLD.add(foldAccents(w)); prev=w;
  }
  return DICT_FR;
}
/* Construction asynchrone non bloquante au chargement */
if(typeof window!=='undefined'){ setTimeout(_buildFR,30); }

