const GAME_WORDS_EN=["apple","arrow","armor","atlas","beach","brain","blade","blast","brick","breeze","castle","cloud","cobra","coral","crown","crystal","candle","comet","delta","dragon","dagger","desert","diamond","eagle","empire","ember","flame","flash","fleet","forge","forest","falcon","frost","giant","globe","grace","ghost","glass","guard","glacier","heart","hero","horse","hammer","harbor","haven","hawk","island","ivory","jaguar","jungle","jewel","king","knight","laser","legend","lion","lotus","lance","lava","lantern","lightning","magic","marble","metal","mirror","moon","mountain","meteor","mirage","night","noble","nimbus","nebula","nymph","ocean","orbit","oracle","onyx","opal","pearl","planet","pirate","plume","power","prism","phoenix","quartz","queen","quest","ranger","raven","realm","river","robot","rocket","ruby","rune","ridge","raptor","shadow","shield","silver","skull","snake","solar","spark","spirit","storm","sword","tiger","tower","thunder","titan","torch","thorn","temple","throne","tunnel","twilight","valor","vault","venom","viper","voice","vortex","victor","voyage","water","warrior","weapon","witch","world","wind","winter","wolf","wonder","zenith","zone","zebra"];

/* --- VALIDATION TOLERANTE --------------------------------------
   Regle d'or : si le mot EST dans le dico -> valide instantanement.
   Sinon, on tente l'API (bonus). En cas d'echec/incertitude on
   ACCEPTE les mots plausibles : on ne penalise jamais un vrai mot.
----------------------------------------------------------------*/
const _wc={};
function _norm(w){return (w||'').toLowerCase().normalize('NFC').replace(/\s/g,'');}

function isInDict(word,lang='fr'){
  const w=_norm(word);
  if(lang==='en')return DICT_EN.has(w);
  _buildFR();
  return DICT_FR.has(w)||DICT_FR_FOLD.has(foldAccents(w));
}

/* heuristique : un mot "plausible" (lettres reelles, voyelle presente,
   pas 4x la meme lettre d'affilee, longueur raisonnable) */
function _plausible(w){
  if(w.length<2||w.length>20)return false;
  if(!/^[a-zàâäéèêëïîôùûüÿœæçñ-]+$/.test(w))return false;
  if(!/[aeiouyàâäéèêëïîôùûüÿœæ]/.test(w))return false;   // au moins une voyelle
  if(/(.)\1\1/.test(w))return false;                    // pas 3x meme lettre
  return true;
}

async function isValidWord(word, lang='fr'){
  const w=_norm(word);
  if(!w||w.length<2)return false;
  if(isInDict(w,lang))return true;
  const ck=lang+':'+w;
  if(_wc[ck]!==undefined)return _wc[ck];
  // Tentative API (bonus seulement) - timeout court
  try{
    const ctrl=new AbortController();
    const tid=setTimeout(()=>ctrl.abort(),1800);
    let ok=false;
    if(lang==='en'){
      const r=await fetch('https://api.dictionaryapi.dev/api/v2/entries/en/'+encodeURIComponent(w),{signal:ctrl.signal});
      ok=r.ok;
    } else {
      // API FR ouverte (sans cle) : Wiktionnaire via opensearch
      const r=await fetch('https://fr.wiktionary.org/w/api.php?action=opensearch&limit=1&format=json&origin=*&search='+encodeURIComponent(w),{signal:ctrl.signal});
      if(r.ok){const j=await r.json();ok=Array.isArray(j)&&j[1]&&j[1].some(s=>_norm(s)===w);}
    }
    clearTimeout(tid);
    if(ok){_wc[ck]=true;(lang==='en'?DICT_EN:_buildFR()).add(w);return true;}
  }catch{}
  // FALLBACK TOLERANT : on accepte tout mot plausible (anti-frustration)
  const fb=_plausible(w);
  _wc[ck]=fb; return fb;
}

function getGameWords(lang='fr'){return lang==='en'?GAME_WORDS_EN.slice():GAME_WORDS_FR.slice();}
